describe('InventoryOverview Construction Date Tests', () => {
  let queryClient: QueryClient;
  let mockToast: jest.Mock;
  let mockApiRequest: jest.Mock;

  const defaultProps = {
    className: 'test-class',
    buildingId: 'test-building-id',
    organizationId: 'test-org-id',
    building: {
      id: 'test-building-id',
      name: 'Test Building',
      constructionDate: '2020-06-15',
    },
  };

  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: {
        queries: { retry: false },
        mutations: { retry: false },
      },
    });

    jest.clearAllMocks();
    
    const { useToast } = require('@/hooks/use-toast');
    const { apiRequest } = require('@/lib/queryClient');
    mockToast = useToast().toast;
    mockApiRequest = apiRequest as jest.Mock;

    mockApiRequest.mockResolvedValue({
      ok: true,
      json: async () => ({ success: true, data: [] }),
    });

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      json: async () => ([]),
    });
  });

  afterEach(() => {
    jest.resetAllMocks();
  });

  const renderComponent = (props = {}) => {
    const combinedProps = { ...defaultProps, ...props };
    return render(
      <QueryClientProvider client={queryClient}>
        <InventoryOverview {...combinedProps} />
      </QueryClientProvider>
    );
  };

  describe('Construction Date Display', () => {
    it('should display construction date when provided', async () => {
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByText(/2020-06-15/)).toBeInTheDocument();
      });
    });

    it('should display dash when construction date is not provided', async () => {
      renderComponent({
        building: {
          id: 'test-building-id',
          name: 'Test Building',
          constructionDate: undefined,
        },
      });
      
      await waitFor(() => {
        expect(screen.queryByText(/Loading/)).not.toBeInTheDocument();
      });
      
      const dateDisplay = screen.getByText('—');
      expect(dateDisplay).toBeInTheDocument();
    });

    it('should display dash when construction date is null', async () => {
      renderComponent({
        building: {
          id: 'test-building-id',
          name: 'Test Building',
          constructionDate: null,
        },
      });
      
      await waitFor(() => {
        expect(screen.queryByText(/Loading/)).not.toBeInTheDocument();
      });
      
      const dateDisplay = screen.getByText('—');
      expect(dateDisplay).toBeInTheDocument();
    });

    it('should show edit button for construction date', async () => {
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
      });
    });
  });

  describe('Construction Date Editing State Management', () => {
    it('should enter edit mode when edit button is clicked', async () => {
      const user = userEvent.setup();
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
      });
      
      const editButton = screen.getByTestId('edit-construction-date');
      await user.click(editButton);
      
      expect(screen.getByTestId('construction-date-input')).toBeInTheDocument();
      expect(screen.getByTestId('save-construction-date')).toBeInTheDocument();
      expect(screen.getByTestId('cancel-edit-construction-date')).toBeInTheDocument();
    });

    it('should exit edit mode when cancel button is clicked', async () => {
      const user = userEvent.setup();
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
      });
      
      await user.click(screen.getByTestId('edit-construction-date'));
      await user.click(screen.getByTestId('cancel-edit-construction-date'));
      
      expect(screen.queryByTestId('construction-date-input')).not.toBeInTheDocument();
      expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
    });

    it('should sync editingDate with building prop on mount', async () => {
      renderComponent({
        building: {
          id: 'test-building-id',
          name: 'Test Building',
          constructionDate: '2021-12-25',
        },
      });
      
      await waitFor(() => {
        expect(screen.getByText(/2021-12-25/)).toBeInTheDocument();
      });
    });

    it('should update editingDate when building prop changes', async () => {
      const { rerender } = renderComponent();
      
      await waitFor(() => {
        expect(screen.getByText(/2020-06-15/)).toBeInTheDocument();
      });
      
      rerender(
        <QueryClientProvider client={queryClient}>
          <InventoryOverview
            {...defaultProps}
            building={{
              id: 'test-building-id',
              name: 'Test Building',
              constructionDate: '2022-01-01',
            }}
          />
        </QueryClientProvider>
      );
      
      await waitFor(() => {
        expect(screen.getByText(/2022-01-01/)).toBeInTheDocument();
      });
    });
  });

  describe('Construction Date Calendar Picker', () => {
    it('should show date input in edit mode', async () => {
      const user = userEvent.setup();
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
      });
      
      await user.click(screen.getByTestId('edit-construction-date'));
      
      expect(screen.getByTestId('construction-date-input')).toBeInTheDocument();
    });

    it('should maintain construction date display', async () => {
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByText(/2020-06-15/)).toBeInTheDocument();
      });
    });
  });

  describe('Construction Date Mutations and Cache Invalidation', () => {
    it('should call apiRequest when saving construction date', async () => {
      const user = userEvent.setup();
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByTestId('edit-construction-date')).toBeInTheDocument();
      });
      
      await user.click(screen.getByTestId('edit-construction-date'));
      await user.click(screen.getByTestId('save-construction-date'));
      
      await waitFor(() => {
        expect(mockApiRequest).toHaveBeenCalled();
      });
    });
  });

  describe('Component Props and Edge Cases', () => {
    it('should handle missing building prop', () => {
      renderComponent({ building: undefined });
      
      expect(screen.getByText('Inventory Overview')).toBeInTheDocument();
    });

    it('should handle missing buildingId', () => {
      renderComponent({ buildingId: undefined });
      
      expect(screen.getByText('Inventory Overview')).toBeInTheDocument();
    });

    it('should handle missing organizationId', () => {
      renderComponent({ organizationId: undefined });
      
      expect(screen.getByText('Inventory Overview')).toBeInTheDocument();
    });

    it('should apply custom className', () => {
      renderComponent({ className: 'custom-class' });
      
      const overview = screen.getByTestId('inventory-overview');
      expect(overview).toHaveClass('custom-class');
    });
  });

  describe('Collapsible Functionality', () => {
    it('should start collapsed by default', () => {
      renderComponent();
      
      const collapsible = screen.getByTestId('inventory-overview');
      expect(collapsible).toHaveAttribute('data-open', 'false');
    });

    it('should show construction date after loading', async () => {
      renderComponent();
      
      await waitFor(() => {
        expect(screen.getByText(/2020-06-15/)).toBeInTheDocument();
      });
    });
  });

  describe('Date Formatting and Validation', () => {
    it('should handle different date formats from building prop', async () => {
      renderComponent({
        building: {
          id: 'test-building-id',
          name: 'Test Building',
          constructionDate: '2020-06-15',
        },
      });

      await waitFor(() => {
        expect(screen.getByText(/2020-06-15/)).toBeInTheDocument();
      });
    });
  });
});
